import{_ as a,c as s,o as e,a1 as i}from"./chunks/framework.C2mR__yb.js";const t="/assets/node.CoaK_weK.jpg",b=JSON.parse('{"title":"Npm","description":"","frontmatter":{},"headers":[],"relativePath":"guide/tool/npm.md","filePath":"guide/tool/npm.md"}'),n={name:"guide/tool/npm.md"},l=i('<h1 id="npm" tabindex="-1">Npm <a class="header-anchor" href="#npm" aria-label="Permalink to &quot;Npm&quot;">​</a></h1><h2 id="安装配置" tabindex="-1">安装配置 <a class="header-anchor" href="#安装配置" aria-label="Permalink to &quot;安装配置&quot;">​</a></h2><p><img src="'+t+`" alt="An image" loading="lazy"></p><p>NPM是随同NodeJS一起安装的包管理工具，是常用的前端包管理工作</p><p>访问 <a href="https://nodejs.org/zh-cn/" target="_blank" rel="noreferrer">nodejs (opens new window)</a>官网下载安装 nodejs , 其中将内置npm命令</p><h2 id="版本号" tabindex="-1">版本号 <a class="header-anchor" href="#版本号" aria-label="Permalink to &quot;版本号&quot;">​</a></h2><p>在安装时版本号是很关键的，大家要清楚版本更新规则</p><h3 id="版本号说明" tabindex="-1">版本号说明 <a class="header-anchor" href="#版本号说明" aria-label="Permalink to &quot;版本号说明&quot;">​</a></h3><p>版本示例: <strong>a.b.c</strong> 表示 <strong>主版本号.次版本号.修补版本号</strong></p><ul><li>a 兼容版本，一般来讲版本<code>2.0.0</code>不一定向<code>1.0.0</code>兼容，所以这个版本号更新要慎重</li><li>b 次版本号，一般为功能上的升级</li><li>c 修订号，一般指对程序<code>bug</code>的修复</li></ul><h3 id="指定版本" tabindex="-1">指定版本 <a class="header-anchor" href="#指定版本" aria-label="Permalink to &quot;指定版本&quot;">​</a></h3><p>可以通过<code>^ 、~ 、*</code>来指定版本号</p><ul><li><code>^</code>表示与版本兼容，指从最左边非0算起，该数值不能变 <ol><li>版本号<code>^2.1.0</code>：指<code>&gt;= 2.1.0</code>但<code>&lt; 3.0.0</code></li><li>版本号<code>^0.2.1</code>：指<code>&gt;= 0.2.1</code>但<code>&lt; 0.3.0</code></li><li>版本号<code>^0.1.0</code>：指<code>&gt;= 0.1.0</code>但<code>&lt; 0.2.0</code></li></ol></li><li><code>~</code>表示次版本号的更新规则，指从最右边非 0 算起，该数值不能变 <ol><li><code>~2.1.0</code>：指<code>&gt;=2.1.0</code>但<code>&lt;2.2.0</code></li><li><code>~2.2.0</code>：指<code>&gt;=2.0.0</code>但<code>=2.0.0</code>因为次版本号为0</li></ol></li><li><code>*</code>表示任意版本，永远更新最新版本</li><li><code>-</code>表示版本区间 <ul><li><code>1.2.1-1.6.5</code>：指 <code>1.2.1与1.6.5</code>间的任意版本</li></ul></li></ul><h3 id="锁定版本" tabindex="-1">锁定版本 <a class="header-anchor" href="#锁定版本" aria-label="Permalink to &quot;锁定版本&quot;">​</a></h3><p>每次更新版本后会生成yarn.lock文件，用于记录当前项目的使用的软件版本号，这样别人执行 <code>yarn</code>安装包时与项目开发者使用的是相同版本，来保证程序的稳定运行</p><h2 id="常用命令" tabindex="-1">常用命令 <a class="header-anchor" href="#常用命令" aria-label="Permalink to &quot;常用命令&quot;">​</a></h2><h3 id="安装软件" tabindex="-1">安装软件 <a class="header-anchor" href="#安装软件" aria-label="Permalink to &quot;安装软件&quot;">​</a></h3><p><strong>全局安装</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npm install -g &lt;Module Name&gt;</span></span></code></pre></div><p>安装软件包，但不修改package.json 文件，以后使用npm install 时不会自动安装</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npm install &lt;Module Name&gt;</span></span></code></pre></div><p><strong>生产环境</strong></p><ul><li>在<code>package.json</code>文件<code>dependencies</code>属性下增加记录</li><li><code>npm install</code>是会自动安装该软件包</li><li>使用<code>npm install --production</code>或者<code>NODE_ENV</code>变量值为<code>production</code>时，安装该软件包</li></ul><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">npm install </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">save </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;module</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//简写</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> install</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> -</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">S</span></span></code></pre></div><p><strong>开发环境</strong></p><ul><li>在package.json文件devDependencies属性下增加记录</li><li>npm install 时会自动安装该软件包</li><li>使用npm install --production或者NODE_ENV变量值为production时，不会安装该软件包</li></ul><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">npm install </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">save</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dev </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Module Name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    </span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//简写</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">npm install </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">D</span></span></code></pre></div><h3 id="查看软件" tabindex="-1">查看软件 <a class="header-anchor" href="#查看软件" aria-label="Permalink to &quot;查看软件&quot;">​</a></h3><p>查看安装的模块列表</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npm ls</span></span></code></pre></div><p>查看本地已安装的包信息</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npm ls tailwindcss</span></span>
<span class="line"><span>或</span></span>
<span class="line"><span>npm ls | grep tailwind</span></span></code></pre></div><p>查看包信息</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npm info tailwindcss</span></span>
<span class="line"><span>或</span></span>
<span class="line"><span>npm view tailwindcss</span></span></code></pre></div><p>列出项目的依赖</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npm list</span></span></code></pre></div><p>列出项目的依赖，并限制显示的依赖深度</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npm list --depth=2</span></span></code></pre></div><h3 id="更新软件" tabindex="-1">更新软件 <a class="header-anchor" href="#更新软件" aria-label="Permalink to &quot;更新软件&quot;">​</a></h3><p>更新npm自身</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npm install npm -g</span></span></code></pre></div><p>更新所有软件包</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npm update</span></span></code></pre></div><p>更新指定软件包</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npm update &lt;Module Name&gt;</span></span></code></pre></div><h3 id="卸载软件" tabindex="-1">卸载软件 <a class="header-anchor" href="#卸载软件" aria-label="Permalink to &quot;卸载软件&quot;">​</a></h3><p>删除全局软件</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npm uninstall -g &lt;Module Name&gt;</span></span></code></pre></div><p>删除项目中软件包</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npm uninstall &lt;Module Name&gt;</span></span></code></pre></div><h3 id="npx" tabindex="-1">npx <a class="header-anchor" href="#npx" aria-label="Permalink to &quot;npx&quot;">​</a></h3><p>node安装后会提供npx命令，使用npx命令可以直接调用模块命令。</p><p>下面是不使用npx调用mockjs中的random命令方式</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>node_modules/mockjs/bin/random</span></span></code></pre></div><p>使用npx可以简化调用，他会在<code>node_modules/.bin</code> 目录和环境变量<code>$PATH</code>中查找命令并执行</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npx random</span></span></code></pre></div>`,56),p=[l];function o(d,c,h,r,g,k){return e(),s("div",null,p)}const m=a(n,[["render",o]]);export{b as __pageData,m as default};
